class Solution:
  def fix_css_variables(self, css_string) -> str:
    # Split the CSS string into selectors
    selectors = css_string.split('}');

    # Initialize an empty list to store the corrected selectors
    corrected_selectors = [];

    # Iterate over each selector
    for selector in selectors:
      # Split the selector into parts
      parts = selector.split(' ');;

      # Initialize a stack to keep track of the current selector scope
      scope_stack = [];

      # Iterate over each part
      for part in parts:
        # Check if the part is a CSS variable
        if part.startswith('--'):
          # Update the variable priority by pushing the current scope to the stack
          scope_stack.append(part);
        elif part == '{':
          # Update the variable priority by popping the current scope from the stack
          scope_stack.pop();
      # Join the corrected parts back into a selector
      corrected_selector = ' '.join(parts) + '}';
      corrected_selectors.append(corrected_selector);

    # Join the corrected selectors back into a string
    return ''.join(corrected_selectors)
